xpath.script:
if (typeof fbq !== 'undefined') {
    fbq('track', 'ViewContent', {
        content_name: '',
        content_ids: [''],
        content_type: 'product',
        value: ,
        currency: ''
    });
}

if (typeof fbq !== 'undefined') {
    var cartTotal = ;
    var cartCurrency = '';
    var numItems = ;

    if (window.location.pathname.indexOf('/shop/checkout') !== -1 || window.location.pathname.indexOf('/shop/address') !== -1) {
        // User started checkout (One-page checkout)
        fbq('track', 'InitiateCheckout', {
            value: cartTotal,
            currency: cartCurrency,
            num_items: numItems
        });

        // Pass these to global window object so our JS can use them when they click Pay
        window.gf_fb_cartTotal = cartTotal;
        window.gf_fb_cartCurrency = cartCurrency;
    }
}

if (typeof fbq !== 'undefined') {
    // This event_id MUST match exactly the one sent by the Python backend API
    // so Facebook can correctly deduplicate them and not double-count the sale.
    fbq('track', 'Purchase', {
        value: ,
        currency: '',
        content_type: 'product',
        content_ids: ['',]
    }, {
        eventID: 'ORDER_'
    });
}
